mapper.select:
SELECT t.id, c.name AS courseName, cr.name AS classroomName, th.name AS teacherName, t.media_type AS mediaType, t.status, t.attendance_count AS attendanceCount, t.total_score AS totalScore, t.retry_count AS retryCount, t.fail_reason AS failReason, t.created_at AS createdAt, t.start_time AS startTime, t.finish_time AS finishTime, TIMESTAMPDIFF(SECOND, t.start_time, t.finish_time) AS durationSeconds FROM analysis_task t LEFT JOIN course_schedule cs ON t.schedule_id = cs.id LEFT JOIN course c ON cs.course_id = c.id LEFT JOIN classroom cr ON cs.classroom_id = cr.id LEFT JOIN teacher th ON t.teacher_id = th.id
AND t.teacher_id = #{query.teacherId}
AND t.status = #{query.status}
AND t.media_type = #{query.mediaType}
AND (c.name LIKE CONCAT('%', #{query.keyword}, '%') OR th.name LIKE CONCAT('%', #{query.keyword}, '%') OR cr.name LIKE CONCAT('%', #{query.keyword}, '%'))
AND DATE(t.created_at) >= #{query.startDate}
AND DATE(t.created_at) <= #{query.endDate}
ORDER BY t.created_at DESC
